// src/components/GraphView.jsx
import { useEffect, useRef, useState, useCallback } from 'react';
import { Network, DataSet } from 'vis-network/standalone';
import 'vis-network/styles/vis-network.min.css';
import { THEMES } from '../themes';
import { EmptyState } from './UI';

// Node type colours
const TYPE_COLORS = {
  username: '#ef4444',
  target:   '#ef4444',
  platform: '#06b6d4',
  email:    '#f59e0b',
  phone:    '#a855f7',
  keyword:  '#10b981',
  mention:  '#3b82f6',
  location: '#f97316',
  org:      '#ec4899',
  default:  '#6366f1',
};

const FILTER_TYPES = [
  { key: 'all',      label: '◉ All',       color: '#94a3b8' },
  { key: 'target',   label: '🎯 Target',    color: TYPE_COLORS.target },
  { key: 'platform', label: '📱 Platform',  color: TYPE_COLORS.platform },
  { key: 'email',    label: '📧 Email',     color: TYPE_COLORS.email },
  { key: 'phone',    label: '📞 Phone',     color: TYPE_COLORS.phone },
  { key: 'keyword',  label: '🔑 Keyword',   color: TYPE_COLORS.keyword },
  { key: 'mention',  label: '💬 Mention',   color: TYPE_COLORS.mention },
];

export default function GraphView({ graphData, theme, targetUsername }) {
  const t = THEMES[theme];
  const containerRef = useRef(null);
  const networkRef   = useRef(null);
  const nodesDS      = useRef(null);
  const edgesDS      = useRef(null);

  const [filter, setFilter]   = useState('all');
  const [tooltip, setTooltip] = useState({ visible: false, node: null, x: 0, y: 0 });
  const [stats, setStats]     = useState({ nodes: 0, edges: 0 });
  const [exporting, setExporting] = useState(false);

  const nodes = graphData?.nodes || [];
  const edges = graphData?.edges || [];

  const buildNetwork = useCallback(() => {
    if (!containerRef.current || !nodes.length) return;

    // Destroy existing
    if (networkRef.current) {
      networkRef.current.destroy();
      networkRef.current = null;
    }

    // Enrich nodes with colours
    const enrichedNodes = nodes.map(n => {
      const isTarget = n.id === `user_${targetUsername}` || n.group === 'target' || n.label === targetUsername;
      const group = isTarget ? 'target' : (n.group || 'default');
      const color = TYPE_COLORS[group] || TYPE_COLORS.default;
      return {
        ...n,
        color: {
          background: isTarget ? '#ef4444' : color,
          border:     isTarget ? '#ff6666' : `${color}cc`,
          highlight:  { background: color, border: '#fff' },
          hover:      { background: `${color}dd`, border: '#fff' },
        },
        size: isTarget ? 28 : (n.size || 16),
        font: {
          size: isTarget ? 15 : 12,
          color: '#fff',
          face: 'Sora, sans-serif',
          strokeWidth: 3,
          strokeColor: '#000',
          bold: isTarget,
        },
        shadow: isTarget ? { enabled: true, color: '#ef4444', size: 20, x: 0, y: 0 } : { enabled: false },
        borderWidth: isTarget ? 3 : 1.5,
        _isTarget: isTarget,
        _group: group,
      };
    });

    nodesDS.current = new DataSet(enrichedNodes);
    edgesDS.current = new DataSet(edges.map(e => ({
      ...e,
      color: { color: `${t.accent}55`, highlight: t.accent, hover: t.accentAlt },
      width: e.value ? Math.min(e.value * 2, 6) : 1.5,
      font: { size: 9, color: t.textMuted, face: 'JetBrains Mono, monospace', align: 'middle' },
      smooth: { type: 'curvedCW', roundness: 0.15 },
      arrows: { to: { enabled: true, scaleFactor: 0.6 } },
    })));

    const options = {
      physics: {
        enabled: true,
        barnesHut: {
          gravitationalConstant: -28000,
          centralGravity: 0.35,
          springLength: 180,
          springConstant: 0.04,
          damping: 0.09,
        },
        maxVelocity: 60,
        stabilization: { iterations: 150 },
      },
      interaction: {
        hover: true,
        keyboard: { enabled: true, bindToWindow: false },
        tooltipDelay: 200,
        multiselect: false,
      },
      configure: false,
    };

    networkRef.current = new Network(
      containerRef.current,
      { nodes: nodesDS.current, edges: edgesDS.current },
      options
    );

    networkRef.current.on('stabilized', () => {
      networkRef.current.fit({ animation: { duration: 800, easingFunction: 'easeInOutQuad' } });
    });

    networkRef.current.on('hoverNode', (params) => {
      const nodeId = params.node;
      const nodeData = nodesDS.current.get(nodeId);
      setTooltip({
        visible: true,
        node: nodeData,
        x: params.pointer.DOM.x,
        y: params.pointer.DOM.y,
      });
    });

    networkRef.current.on('blurNode', () => {
      setTooltip(prev => ({ ...prev, visible: false }));
    });

    networkRef.current.on('click', (params) => {
      if (!params.nodes.length) return;
    });

    setStats({ nodes: nodes.length, edges: edges.length });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [graphData, theme]);

  useEffect(() => {
    buildNetwork();
    return () => {
      if (networkRef.current) {
        networkRef.current.destroy();
        networkRef.current = null;
      }
    };
  }, [buildNetwork]);

  // Apply node type filter
  const applyFilter = useCallback((type) => {
    setFilter(type);
    if (!nodesDS.current) return;
    const all = nodesDS.current.get();
    nodesDS.current.update(
      all.map(n => ({
        id: n.id,
        hidden: type !== 'all' && n._group !== type && !(type === 'target' && n._isTarget),
      }))
    );
  }, []);

  const handleFit = () => networkRef.current?.fit({ animation: { duration: 600, easingFunction: 'easeInOutQuad' } });
  const handleZoomIn  = () => networkRef.current?.moveTo({ scale: (networkRef.current.getScale() * 1.25) });
  const handleZoomOut = () => networkRef.current?.moveTo({ scale: (networkRef.current.getScale() * 0.8) });

  const handleExportPng = async () => {
    if (!networkRef.current || !containerRef.current) return;
    setExporting(true);
    try {
      const canvas = containerRef.current.querySelector('canvas');
      if (canvas) {
        const url = canvas.toDataURL('image/png');
        const a = document.createElement('a');
        a.href = url;
        a.download = `osint-graph-${Date.now()}.png`;
        a.click();
      }
    } finally {
      setExporting(false);
    }
  };

  if (!nodes.length && !edges.length) {
    return <EmptyState icon="🕸" message="No network graph data available for this investigation." theme={theme} />;
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>

      {/* Controls bar */}
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        flexWrap: 'wrap', gap: 10,
      }}>
        {/* Node type filters */}
        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
          {FILTER_TYPES.map(f => (
            <button
              key={f.key}
              onClick={() => applyFilter(f.key)}
              style={{
                padding: '5px 12px',
                background: filter === f.key ? `${f.color}33` : t.surfaceAlt,
                border: `1px solid ${filter === f.key ? f.color : t.border}`,
                borderRadius: 20,
                color: filter === f.key ? f.color : t.textMuted,
                cursor: 'pointer',
                fontFamily: "'Sora',sans-serif",
                fontSize: 11,
                fontWeight: filter === f.key ? 700 : 500,
                transition: 'all 0.15s',
              }}
            >
              {f.label}
            </button>
          ))}
        </div>

        {/* Graph stats */}
        <div style={{ display: 'flex', gap: 14, alignItems: 'center' }}>
          <span style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 10, color: t.textMuted }}>
            {stats.nodes} nodes · {stats.edges} edges
          </span>
        </div>
      </div>

      {/* Graph canvas */}
      <div style={{ position: 'relative', width: '100%', height: 500, borderRadius: 12, overflow: 'hidden' }}>
        <div
          ref={containerRef}
          style={{
            width: '100%', height: '100%',
            background: t.surfaceAlt,
            border: `1px solid ${t.border}`,
            borderRadius: 12,
          }}
        />

        {/* Zoom / Fit / Export buttons */}
        <div style={{ position: 'absolute', top: 12, right: 12, display: 'flex', flexDirection: 'column', gap: 6, zIndex: 10 }}>
          {[
            { label: '+', onClick: handleZoomIn,  title: 'Zoom in' },
            { label: '−', onClick: handleZoomOut, title: 'Zoom out' },
            { label: '⊞', onClick: handleFit,     title: 'Fit view' },
          ].map(btn => (
            <button
              key={btn.label}
              onClick={btn.onClick}
              title={btn.title}
              style={graphCtrlBtn(t)}
            >
              {btn.label}
            </button>
          ))}
          <button
            onClick={handleExportPng}
            title="Export PNG"
            style={{ ...graphCtrlBtn(t), fontSize: 11, padding: '7px 8px' }}
          >
            {exporting ? '…' : '⬇'}
          </button>
        </div>

        {/* Hover tooltip */}
        {tooltip.visible && tooltip.node && (
          <div style={{
            position: 'absolute',
            left: Math.min(tooltip.x + 14, 380),
            top:  Math.max(tooltip.y - 60, 8),
            background: `${t.surface}f0`,
            border: `1px solid ${t.accent}66`,
            borderRadius: 8,
            padding: '10px 14px',
            zIndex: 20,
            maxWidth: 220,
            backdropFilter: 'blur(8px)',
            pointerEvents: 'none',
          }}>
            <div style={{ fontFamily: "'Sora',sans-serif", fontWeight: 700, fontSize: 12, color: t.text, marginBottom: 4 }}>
              {tooltip.node.label || tooltip.node.id}
            </div>
            {tooltip.node._group && (
              <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 9, color: TYPE_COLORS[tooltip.node._group] || t.textSub, letterSpacing: 1 }}>
                TYPE: {(tooltip.node._group || '').toUpperCase()}
              </div>
            )}
            {tooltip.node.title && (
              <div style={{ fontFamily: "'Sora',sans-serif", fontSize: 11, color: t.textMuted, marginTop: 6, lineHeight: 1.4 }}>
                {tooltip.node.title}
              </div>
            )}
          </div>
        )}

        {/* Legend */}
        <div style={{
          position: 'absolute', bottom: 12, left: 12, zIndex: 10,
          background: `${t.surface}dd`,
          border: `1px solid ${t.border}`,
          borderRadius: 8, padding: '10px 14px',
          backdropFilter: 'blur(8px)',
        }}>
          <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 9, color: t.textSub, letterSpacing: 2, marginBottom: 8, fontWeight: 700 }}>
            LEGEND
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
            {Object.entries(TYPE_COLORS).filter(([k]) => k !== 'default').map(([key, color]) => (
              <div key={key} style={{ display: 'flex', alignItems: 'center', gap: 7 }}>
                <div style={{ width: 10, height: 10, borderRadius: '50%', background: color, flexShrink: 0 }} />
                <span style={{ fontFamily: "'Sora',sans-serif", fontSize: 10, color: t.textMuted, textTransform: 'capitalize' }}>
                  {key}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Keyboard hint */}
      <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 9, color: t.textMuted, letterSpacing: 1 }}>
        ← → ↑ ↓ scroll to pan · +/− to zoom · Click node to select · Export PNG via ⬇ button
      </div>
    </div>
  );
}

function graphCtrlBtn(t) {
  return {
    width: 32, height: 32,
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    background: `${t.surface}dd`,
    border: `1px solid ${t.border}`,
    borderRadius: 6,
    color: t.text,
    cursor: 'pointer',
    fontFamily: "'Sora',sans-serif",
    fontWeight: 700,
    fontSize: 16,
    backdropFilter: 'blur(4px)',
    transition: 'border-color 0.15s',
  };
}
